import sys
import math

def solve(n, k, x, y, c):
    def check(t):
        cnt = 0
        for i in range(n):
            if math.sqrt((x[i] - x0) ** 2 + (y[i] - y0) ** 2) <= t * c[i]:
                cnt += 1
        return cnt >= k

    def binary_search():
        left = 0
        right = 1000
        for _ in range(100):
            mid = (left + right) / 2
            if check(mid):
                right = mid
            else:
                left = mid
        return left

    ans = 1000
    for i in range(n):
        for j in range(n):
            if i != j:
                x0 = (x[i] + x[j]) / 2
                y0 = (y[i] + y[j]) / 2
                ans = min(ans, binary_search())
    return ans

n, k = map(int, sys.stdin.readline().split())
x = []
y = []
c = []
for _ in range(n):
    x_i, y_i, c_i = map(int, sys.stdin.readline().split())
    x.append(x_i)
    y.append(y_i)
    c.append(c_i)

print(solve(n, k, x, y, c))
